def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 8:
            for a in range(8, 3, -1):
                acc_inner = 0.0
                for b in range(1, a + 5):
                    denom = (a*b*0.7 + 0.9)
                    val = ((ratio - a) ** 6) * np.sin(ratio * b / (a + 1)) / denom
                    acc_inner += val * np.cos(ratio * b * 0.9)
                priority += np.log1p(acc_inner) * np.exp(-(ratio - a) / 2) * 7
            priority += np.tanh(np.exp(ratio - 8) * np.sin(ratio * 1.3)) * 5
            if i % 2 == 0:
                priority += np.sin(ratio * i) * 3.3
            else:
                priority -= np.cos(ratio * i) * 3.3
        elif 5 < ratio <= 8:
            acc = 0.0
            for c in range(1, int(ratio)+5):
                for d in range(1, c + 4):
                    term = ((ratio - c) ** 4) * np.cos(ratio * c) / (d + 0.2)
                    acc += np.tanh(term) * 1.5
            priority = acc + np.log(ratio) * 12 - np.tanh(ratio - 5) * 3
            for e in range(1, 5):
                priority += np.sin(e * ratio * i) * ((ratio - 5) ** e) / (e + 1.1)
        elif 2 < ratio <= 5:
            s = 0.0
            for f in range(1, 15):
                s += ((ratio - 2) ** f) / (f * 2) * np.sin(f * ratio * 1.1)
            priority = (s * np.cos(5 * ratio)) - np.log(ratio) * 7 + np.tanh(3 * (5 - ratio)) * 2
            if bin_cap < item * 1.4:
                priority += np.sqrt(item / (bin_cap + 1)) * 3
            else:
                priority -= np.cos(15 * ratio) * 2
        elif 1 <= ratio <= 2:
            s = 0.0
            for g in range(1, 12):
                s += ((2 - ratio) ** g) / (g ** 1.5 + 0.7) * np.cos(g * ratio * 1.8)
            penalty = 0
            if bin_cap > item * 1.2:
                penalty = np.exp(-ratio) * 4
            else:
                penalty = np.log1p(item * bin_cap) * 2.5
            priority = s + penalty
            for h in range(1, 6):
                priority += np.sin(h * ratio * i * 0.8) * ((ratio - 1) ** h) / (h + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0.0
            for j in range(1, 18):
                s += ((1 - ratio) ** j) / (j * 3.5) * np.sin(j * item * 0.7)
            priority = s
            if (i * int(item * 2)) % 3 == 0:
                priority *= np.log1p(bin_cap * 2) * 1.1
            else:
                priority /= (np.sqrt(bin_cap + 2) + 1.8)
            for k in range(1, 8):
                priority += ((1 - ratio) ** k) * np.cos(k * item * 1.1) * 0.8
            if bin_cap < item * 0.7:
                priority += np.exp(-(bin_cap / item)) * 3
        elif 0.2 <= ratio < 0.5:
            s = 0.0
            for l in range(1, 20):
                s += ((0.5 - ratio) ** l) / (l * 4.5) * np.cos(l * ratio * 2.2)
            priority = s + 1.0 / (bin_cap + 2.5)
            if int(item * 0.9) % 3 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.4) * 4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7.5) * np.sin(item * m * 0.9)
        else:
            s = 0.0
            for n in range(1, 14):
                s += ((0.2 - ratio) ** n) / (n * 6) * np.sin(n * item * 0.85)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.6) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.3) * 5
            for o in range(1, 9):
                priority += ((0.2 - ratio) ** o) / (o * 8) * np.cos(item * o * 0.75)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6
            for p in range(1, 6):
                priority += np.sin(p * ratio * i * 1.2) * 0.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
            for q in range(1, 5):
                priority -= np.cos(q * ratio * i * 0.9) * 0.4
        for r in range(1, 6):
            if (i + r) % 4 == 0:
                priority += np.sin(ratio * (i + r) * 0.8) * 0.35
            else:
                priority -= np.cos(ratio * (i + r) * 0.8) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if i % 5 == 0:
            priority += np.tanh(ratio * i * 0.9) * 0.9
        else:
            priority -= np.tanh(ratio * i * 0.7) * 0.9
        priorities[i] = priority
    return priorities
